{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires finding a sequence of sibling merges to transform one tree into another. This involves identifying which nodes in the initial tree must be merged to match the structure and node values of the final tree, while respecting the rule that only siblings can be merged and the larger value is preserved.",
  "helpers": [
    {
      "label": "tree_structure_analyzer",
      "instructions": "Analyze the initial and final trees to identify the mapping between nodes. Specifically, for each node in the final tree, identify which set of nodes in the initial tree (its ancestors or siblings) must have been merged to form it. Determine the parent-child relationships in both trees to identify which nodes are siblings in the initial tree that need to be merged."
    },
    {
      "label": "merge_sequence_generator",
      "instructions": "Given the mapping of initial nodes to final nodes, generate a valid sequence of merge operations. A merge operation is valid if it involves two siblings in the current state of the tree. Ensure that the order of merges respects the tree hierarchy (e.g., merging children before parents or vice versa as required by the problem constraints) and that the larger value rule is satisfied by the input guarantee."
    }
  ],
  "synthesis_brief": "Combine the structural mapping from the analyzer with the sequence of operations from the generator to produce the final Python script. The script must read the input, perform the analysis, output the number of merges, and list each pair of nodes to be merged."
}

